import torch
from transformers import pipeline, LongformerTokenizer, LongformerForQuestionAnswering

# Load company documents into vector database
documents = [
    "Company document 1 content",
    "Company document 2 content",
    "Company document 3 content",
    # Add more documents as needed
]

# Initialize Longformer model and tokenizer
tokenizer = LongformerTokenizer.from_pretrained('allenai/longformer-large-4096')
model = LongformerForQuestionAnswering.from_pretrained('allenai/longformer-large-4096')

# Define the RAG pipeline
rag_pipeline = pipeline('text-generation', model=model, tokenizer=tokenizer)

# Accept user query
user_query = input("Enter your query: ")

# Retrieve relevant context
retrieved_context = ""
for doc in documents:
    input_text = f"{user_query} Document: {doc}"
    retrieved_context += input_text + " "

# Include all retrieved documents in LLM prompt
rag_input = f"{user_query} Context: {retrieved_context}"

# Generate response using RAG
response = rag_pipeline(rag_input, max_length=200, num_return_sequences=1)

print(response[0]['generated_text'])